import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Änderungsprotokoll: Versionsentwicklung und neue Funktionen | Plannotator","description":"Lernen Sie die Versionshistorie von Plannotator und die Veröffentlichung neuer Funktionen kennen. Erfahren Sie mehr über die Verbesserungen, Bugfixes und die Entwicklung von Funktionen wie Code-Reviews und Bildannotationen in jeder Version.","frontmatter":{"title":"Änderungsprotokoll: Versionsentwicklung und neue Funktionen | Plannotator","sidebarTitle":"Neue Funktionen ansehen","subtitle":"Änderungsprotokoll: Versionsentwicklung und neue Funktionen | Plannotator","description":"Lernen Sie die Versionshistorie von Plannotator und die Veröffentlichung neuer Funktionen kennen. Erfahren Sie mehr über die Verbesserungen, Bugfixes und die Entwicklung von Funktionen wie Code-Reviews und Bildannotationen in jeder Version.","order":6},"headers":[],"relativePath":"de/backnotprop/plannotator/changelog/index.md","filePath":"de/backnotprop/plannotator/changelog/index.md"}'),o={name:"de/backnotprop/plannotator/changelog/index.md"};function a(s,e,d,l,u,h){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="anderungsprotokoll" tabindex="-1">Änderungsprotokoll <a class="header-anchor" href="#anderungsprotokoll" aria-label="Permalink to &quot;Änderungsprotokoll&quot;">​</a></h1><p>Dieses Kapitel dokumentiert die Versionshistorie von Plannotator, die Veröffentlichung neuer Funktionen und Informationen zu Bugfixes. Es hilft Ihnen, den Entwicklungsweg des Projekts und die neuesten Fortschritte zu verstehen.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><div class="grid-cards"><a href="./release-notes/" class="card"><h3>📋 Versionshistorie</h3><p>Sehen Sie die vollständige Versionshistorie von Plannotator ein, einschließlich neuer Funktionen, Verbesserungen und Bugfixes in jeder Version. Erfahren Sie mehr über den Zeitplan wichtiger Funktionen wie Code-Reviews, Bildannotationen und Obsidian/Bear-Integrationen.</p></a></div><h2 id="leseempfehlungen" tabindex="-1">Leseempfehlungen <a class="header-anchor" href="#leseempfehlungen" aria-label="Permalink to &quot;Leseempfehlungen&quot;">​</a></h2><p>Das Änderungsprotokoll ist für die folgenden Szenarien geeignet:</p><table tabindex="0"><thead><tr><th>Szenario</th><th>Empfehlung</th></tr></thead><tbody><tr><td><strong>Prüfung vor dem Upgrade</strong></td><td>Prüfen Sie neue Funktionen und Breaking Changes der Zielversion</td></tr><tr><td><strong>Funktionserkundung</strong></td><td>Erfahren Sie, welche Funktionen der neuesten Version hinzugefügt wurden</td></tr><tr><td><strong>Fehlerbehebung</strong></td><td>Bestätigen Sie, ob ein bestimmter Bug in der neuen Version behoben wurde</td></tr><tr><td><strong>Versionskompatibilität</strong></td><td>Prüfen Sie die Versionsbeziehung zwischen Plannotator und Claude Code/OpenCode</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Auf dem Laufenden bleiben</p><p>Es wird empfohlen, das Änderungsprotokoll regelmäßig zu prüfen und rechtzeitig auf die neueste Version zu aktualisieren, um neue Funktionen und Sicherheitsfixes zu erhalten.</p></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nachdem Sie das Änderungsprotokoll gelesen haben, können Sie:</p><ul><li>Zurück zu <a href="./../start/getting-started/">Schnellstart</a> gehen, um die Grundlagen zu lernen</li><li><a href="./../faq/common-problems/">Häufige Fragen</a> ansehen, um Probleme bei der Nutzung zu lösen</li><li><a href="./../appendix/api-reference/">API-Referenz</a> lesen, um alle API-Endpunkte kennenzulernen</li></ul>',11)])])}const p=n(o,[["render",a]]);export{c as __pageData,p as default};
